SELECT AVG(wind_speed) AS avg_wind_speed, AVG(temperature) AS avg_temperature
FROM weather_data
WHERE condition_id = (SELECT condition_id FROM weather_conditions WHERE condition_name = 'Sunny');

SELECT standard_name
FROM data_quality_standards
WHERE standard_name LIKE '%Accuracy%';

SELECT standard_name
FROM data_quality_standards
WHERE standard_id = 0;

SELECT COUNT(forecast_id) 
FROM weather_forecasts
WHERE forecast_date = '2022-01-01';
